def build_tree(node, char):
    if node is None:
        return {'val': char.lower(), 'left': None, 'right': None}
    if char.lower() == node['val']:
        return node
    if char.lower() < node['val']:
        node['left'] = build_tree(node['left'], char)
    else:
        node['right'] = build_tree(node['right'], char)
    return node

def process_sequence(sequence):
    root = None
    for char in sequence:
        root = build_tree(root, char)
    return root

